Sure, if you just want to log the error to the console and move on, you can simplify the error handling in your code. Here’s a basic example in JavaScript:

### Example 1: Node.js Function

```javascript
const fs = require('fs');

function readFile(filePath) {
  try {
    const data = fs.readFileSync(filePath, 'utf8');
    console.log(data);
  } catch (error) {
    // Log the error to the console
    console.error('Error reading file:', error.message);
  }
}

// Example usage
const filePath = 'path/to/your/file.txt';
readFile(filePath);
```

### Example 2: Express.js Route Handler

```javascript
const express = require('express');
const app = express();

app.get('/read-file', (req, res) => {
  const filePath = 'path/to/your/file.txt';

  try {
    const data = fs.readFileSync(filePath, 'utf8');
    res.send(data);
  } catch (error) {
    // Log the error to the console
    console.error('Error reading file:', error.message);

    // Send a generic error message to the client
    res.status(500).send('Internal Server Error');
  }
});

app.listen(3000, () => {
  console.log('Server is running on port 3000');
});
```

### Example 3: Frontend JavaScript

If you're working with frontend JavaScript, you can use a similar approach:

```javascript
function fetchData(url) {
  fetch(url)
    .then(response => {
      if (!response.ok) {
        throw new Error('Network response was not ok ' + response.statusText);
      }
      return response.json();
    })
    .then(data => {
      console.log(data);
    })
    .catch(error => {
      // Log the error to the console
      console.error('Fetch error:', error.message);
    });
}

// Example usage
const apiUrl = 'https://api.example.com/data';
fetchData(apiUrl);
```

In each of these examples:
1. The code attempts to perform an operation that might fail (reading a file, fetching data, etc.).
2. If an error occurs, it logs the error message to the console using `console.error`.
3. The program continues running without crashing.

This approach ensures that errors are logged for debugging purposes while allowing the application to continue running.
